4	  customer: { yearsWithMHPCO: number };
5	  steps: QuoteStep[];
6	};
7	type QuoteResult = { premium: number };
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const withFirstInsurance = (base: number): number =>
22	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	const itemPremium = (item: Item): number => withFirstInsurance(BASE_PREMIUMS[item.type]);
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_BASE_PREMIUM = 60;
28	
29	const componentsBase = (components: Item[]): number => {
30	  const byType = new Map<string, Item[]>();
31	  for (const c of components) {
32	    const list = byType.get(c.type) ?? [];
33	    list.push(c);
34	    byType.set(c.type, list);
35	  }
36	  let total = 0;
37	  for (const group of byType.values()) {
38	    if (group.length === 3) {
39	      total += BLOCK_BASE_PREMIUM;
40	    } else {
41	      total += group.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
42	    }
43	  }
44	  return total;
45	};
46	
47	const quotePremium = (step: QuoteStep): QuoteResult => {
48	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
49	  const nonComponents = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
50	  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemPremium(item), 0);
51	  const componentTotal = withFirstInsurance(componentsBase(components));
52	  return { premium: Math.ceil(nonComponentTotal + componentTotal + PROCESSING_FEE) };
53	};
54	
55	export const run = (scenario: Scenario): { results: QuoteResult[] } => {
56	  return { results: scenario.steps.map(quotePremium) };
57	};
